/*
 * OCR B GCSE Physics (J259) 21st Century Science — Exam Practice Question Bank
 * 40 written exam-style questions per topic, 1-mark recall to 6-mark extended response.
 * Supports diagram:true for questions requiring a sketch — the practice page renders a
 * drawing canvas alongside the textarea.
 */

const PHYSICS_OCR_B_GCSE_PRACTICE = {

  /* ═══════════════════════════════════════ P1 — Radiation and Waves */
  'P1': {
    name: 'Radiation and Waves',
    questions: [
      { q: 'Define the term "amplitude" of a wave.', marks: 1, markScheme: '• Maximum displacement of a particle/point from its rest (equilibrium) position (1)' },
      { q: 'Define the term "wavelength".', marks: 1, markScheme: '• Distance from one point on a wave to the same point on the next wave (e.g. peak to peak) (1)' },
      { q: 'Define the term "frequency" and give its unit.', marks: 2, markScheme: '• Number of complete waves (cycles) passing a point per second (1)\n• Unit: hertz (Hz) (1)' },
      { q: 'State the wave equation, including units for each quantity.', marks: 2, markScheme: '• v = f × λ (1)\n• v in m/s, f in Hz, λ in m (1)' },
      { q: 'A wave has frequency 250 Hz and wavelength 1.4 m. Calculate its speed.', marks: 2, markScheme: '• v = f × λ = 250 × 1.4 (1)\n• v = 350 m/s (1)' },
      { q: 'A sound wave in air travels at 340 m/s with wavelength 0.85 m. Calculate its frequency.', marks: 2, markScheme: '• f = v / λ = 340 / 0.85 (1)\n• f = 400 Hz (1)' },
      { q: 'Distinguish between a transverse and a longitudinal wave, giving an example of each.', marks: 4, markScheme: '• Transverse: oscillations are perpendicular to the direction of energy transfer (1)\n• Example transverse: light / waves on a rope / water ripples (1)\n• Longitudinal: oscillations are parallel to direction of energy transfer (1)\n• Example longitudinal: sound / ultrasound / P-waves (1)' },
      { q: 'Draw a clearly labelled diagram of a transverse wave, marking the amplitude and wavelength.', marks: 3, diagram: true, markScheme: '• Sinusoidal wave drawn with at least one full wavelength visible (1)\n• Amplitude labelled from rest line to crest/trough (1)\n• Wavelength labelled between two equivalent points (e.g. crest to crest) (1)' },
      { q: 'State, in order of increasing frequency, the seven main regions of the electromagnetic spectrum.', marks: 3, markScheme: '• Radio, microwave, infrared (1)\n• Visible light (1)\n• Ultraviolet, X-ray, gamma (1)' },
      { q: 'State the speed of all electromagnetic waves in a vacuum.', marks: 1, markScheme: '• 3.0 × 10⁸ m/s (accept 300 000 000 m/s / 3 × 10⁸ m/s) (1)' },
      { q: 'Give one use and one hazard of infrared radiation.', marks: 2, markScheme: '• Use: cooking / thermal imaging / TV remote / short-range fibre communication (any 1)\n• Hazard: can cause skin burns if absorbed in large amounts (1)' },
      { q: 'Give one use and one hazard of ultraviolet radiation.', marks: 2, markScheme: '• Use: fluorescent lamps / security marking / disinfecting water / tanning (any 1)\n• Hazard: skin cancer / premature ageing / eye damage (any 1)' },
      { q: 'Give one use and one hazard of X-rays.', marks: 2, markScheme: '• Use: imaging of bones / CT scans / airport security (any 1)\n• Hazard: ionises cells, can cause cancer (1)' },
      { q: 'Give one use and one hazard of gamma radiation.', marks: 2, markScheme: '• Use: sterilising surgical equipment / radiotherapy / medical tracers (any 1)\n• Hazard: ionising, can damage DNA and cause cancer (1)' },
      { q: 'Explain why microwaves rather than radio waves are used for satellite communication.', marks: 3, markScheme: '• Microwaves have shorter wavelengths than radio (1)\n• Short wavelengths pass through the atmosphere/ionosphere without reflection (1)\n• Travel in straight lines to the satellite without diffracting around obstacles (1)' },
      { q: 'Explain why visible light is the only part of the EM spectrum that allows us to see.', marks: 2, markScheme: '• Human eye receptors (rods/cones) are only sensitive to this narrow band (1)\n• Other wavelengths pass through or are absorbed by the eye, stimulating no signal (1)' },
      { q: 'Distinguish between ionising and non-ionising radiation and give two examples of each.', marks: 4, markScheme: '• Ionising: enough energy to knock electrons off atoms, forming ions (1)\n• Examples of ionising: UV / X-rays / gamma / alpha / beta (any 2 of the EM ones = 1)\n• Non-ionising: lower-energy EM radiation that cannot ionise atoms (1)\n• Examples of non-ionising: radio / microwave / infrared / visible (any 2 = 1)' },
      { q: 'Describe what happens to a ray of light when it passes from air into glass.', marks: 3, markScheme: '• Light slows down (1)\n• Ray bends towards the normal (1)\n• Frequency stays the same but wavelength decreases (1)' },
      { q: 'Draw a ray diagram of light passing from air into glass at an angle to the normal. Mark the angle of incidence (i) and angle of refraction (r).', marks: 4, diagram: true, markScheme: '• Boundary between air and glass shown with correct shading (1)\n• Normal drawn (dashed) perpendicular to boundary (1)\n• Incident ray in air with i labelled from normal (1)\n• Refracted ray in glass bending towards normal with r labelled (1)' },
      { q: 'State the law of reflection.', marks: 2, markScheme: '• Angle of incidence = angle of reflection (1)\n• Both measured from the normal (1)' },
      { q: 'A mirror reflects a ray at 35° to the normal. State the angle of incidence.', marks: 1, markScheme: '• 35° (1)' },
      { q: 'Describe how ultrasound is used in medical imaging of a foetus.', marks: 4, markScheme: '• Pulse of ultrasound sent from a transducer into the body (1)\n• Reflected at boundaries between tissues of different densities (1)\n• Time taken for reflections to return used to calculate depth (1)\n• Computer builds an image from the echoes; non-ionising so safe for the foetus (1)' },
      { q: 'A submarine sends a sonar pulse that returns 0.6 s later. Speed of sound in water is 1500 m/s. Calculate the depth to the object.', marks: 3, markScheme: '• Total distance = v × t = 1500 × 0.6 = 900 m (1)\n• Halve because pulse travels there and back (1)\n• Depth = 450 m (1)' },
      { q: 'Explain why gamma rays can be used both to treat and to cause cancer.', marks: 3, markScheme: '• Gamma rays are ionising, damaging cell DNA (1)\n• Damaged DNA in healthy cells can cause uncontrolled cell division → cancer (1)\n• Targeted high doses on a tumour kill cancer cells, which are more susceptible than healthy ones (1)' },
      { q: 'State three ways radiographers reduce their exposure to X-rays at work.', marks: 3, markScheme: '• Stand behind a lead-shielded screen / wear lead apron (1)\n• Increase distance from the source (1)\n• Minimise exposure time / use lowest effective dose (1)' },
      { q: 'A UK adult receives about 2.7 mSv per year of background radiation. A CT scan gives about 10 mSv. Explain why doctors still use CT scans despite this extra dose.', marks: 3, markScheme: '• Extra dose is significant but the information from a CT scan may save a life (1)\n• The risk of cancer from a single scan is small compared with the diagnostic benefit (1)\n• Doctors follow ALARA — use CT only when needed, choose lower-dose alternatives when possible (1)' },
      { q: 'Explain why sound cannot travel through a vacuum.', marks: 2, markScheme: '• Sound is a longitudinal mechanical wave that relies on particles transmitting vibrations (1)\n• A vacuum has no particles so no medium for the wave — it cannot propagate (1)' },
      { q: 'Define ultrasound.', marks: 1, markScheme: '• Sound waves with frequency above 20 000 Hz (the upper limit of human hearing) (1)' },
      { q: 'Suggest why matt black surfaces are used on solar panels but shiny silver on space-suit outer layers.', marks: 3, markScheme: '• Matt black absorbs IR/visible radiation efficiently (1)\n• Solar panels need to absorb as much radiation as possible to generate heat/electricity (1)\n• Shiny silver reflects solar radiation, preventing the astronaut from overheating (1)' },
      { q: 'A wave on a string has a period of 0.04 s. Calculate its frequency.', marks: 2, markScheme: '• f = 1/T = 1/0.04 (1)\n• f = 25 Hz (1)' },
      { q: 'Explain why, when a wave passes from deep to shallow water, it slows down and the wavelength decreases but the frequency does not change.', marks: 4, markScheme: '• Speed is determined by the medium, not by the source (1)\n• Shallow water slows the wave (1)\n• The source still produces the same number of wavefronts per second, so f is unchanged (1)\n• Since v = fλ and v decreases while f is constant, λ must decrease (1)' },
      { q: 'Sketch a pair of waves on the same axes: a loud low-pitched sound and a quiet high-pitched sound.', marks: 3, diagram: true, markScheme: '• Loud low: large amplitude and long wavelength/low frequency (1)\n• Quiet high: small amplitude and short wavelength/high frequency (1)\n• Axes labelled with time and displacement (1)' },
      { q: 'Explain why X-rays are used to image bones but ultrasound is used for soft tissue.', marks: 4, markScheme: '• X-rays are absorbed strongly by dense bone and transmitted through soft tissue (1)\n• This gives a clear shadow image of bones (1)\n• Ultrasound reflects at soft-tissue boundaries, showing internal structure (1)\n• X-rays would damage a foetus; ultrasound is non-ionising and safe (1)' },
      { q: 'Explain the meaning of "radiation dose" and state its unit.', marks: 2, markScheme: '• A measure of the risk of harm to tissue from ionising radiation (takes into account type and amount) (1)\n• Unit: sievert (Sv) (1)' },
      { q: 'A student stands 1 m from a γ source and measures dose rate D. How does the dose rate change at 2 m (ignoring absorption)?', marks: 2, markScheme: '• Intensity obeys an inverse-square relationship (1)\n• Doubling distance gives 1/4 × D (1)' },
      { q: 'Describe one peaceful and one hazardous effect of microwaves.', marks: 2, markScheme: '• Peaceful: cooking food (water in food absorbs microwaves and heats up) / satellite communication (1)\n• Hazardous: internal heating of body tissue at very high intensity (1)' },
      { q: 'Explain why light can be reflected, refracted and absorbed when it hits a window.', marks: 3, markScheme: '• Some light reflects off the glass surface (seen as a faint image of the room) (1)\n• Some refracts as it enters and leaves the glass (slight shift in angle) (1)\n• Some is absorbed by the glass (slight tint / warming) (1)' },
      { q: 'Calculate the wavelength of a FM radio wave with frequency 100 MHz. (c = 3 × 10⁸ m/s)', marks: 2, markScheme: '• λ = c / f = 3 × 10⁸ / 1 × 10⁸ (1)\n• λ = 3 m (1)' },
      { q: 'Explain why radio waves can be received behind a hill, but microwave satellite signals cannot.', marks: 3, markScheme: '• Radio waves have long wavelengths comparable with the hill → they diffract strongly around it (1)\n• Microwaves have shorter wavelengths → diffract little and are blocked (1)\n• Satellite microwaves therefore need line of sight to the dish (1)' },
      { q: '"All electromagnetic waves are the same." Explain why this statement is both true and false.', marks: 6, markScheme: '• TRUE points:\n   – All travel at 3 × 10⁸ m/s in a vacuum (1)\n   – All are transverse (1)\n   – All can be reflected, refracted, diffracted and absorbed (1)\n• FALSE points:\n   – They have a huge range of frequencies/wavelengths (1)\n   – Their energies differ by many orders of magnitude — gamma vastly more than radio (1)\n   – They have very different uses and hazards, and different parts are/aren\'t ionising (1)' },
    ],
  },

  /* ═══════════════════════════════════════ P2 — Sustainable Energy */
  'P2': {
    name: 'Sustainable Energy',
    questions: [
      { q: 'State the Principle of Conservation of Energy.', marks: 1, markScheme: '• Energy cannot be created or destroyed — it is only transferred between stores (1)' },
      { q: 'Name the eight energy stores.', marks: 3, markScheme: '• Kinetic, gravitational potential, elastic potential (1)\n• Thermal (internal), chemical, magnetic (1)\n• Electrostatic, nuclear (1)' },
      { q: 'Name the four energy pathways.', marks: 2, markScheme: '• Mechanical work, electrical work (1)\n• Heating, radiation (1)' },
      { q: 'Define power and state its unit.', marks: 2, markScheme: '• Rate at which energy is transferred (or work is done) (1)\n• Unit: watt (W) = J/s (1)' },
      { q: 'Write the equation linking power, energy and time.', marks: 1, markScheme: '• P = E / t (1)' },
      { q: 'A kettle uses 168 000 J of energy in 120 s. Calculate its power.', marks: 2, markScheme: '• P = E / t = 168 000 / 120 (1)\n• P = 1400 W (1.4 kW) (1)' },
      { q: 'A 60 kg runner moves at 5 m/s. Calculate their kinetic energy.', marks: 2, markScheme: '• Eₖ = ½ m v² = ½ × 60 × 25 (1)\n• Eₖ = 750 J (1)' },
      { q: 'A 2.5 kg book is lifted through 0.8 m. Take g = 9.8 N/kg. Calculate the GPE gained.', marks: 2, markScheme: '• Eₚ = m g h = 2.5 × 9.8 × 0.8 (1)\n• Eₚ = 19.6 J (1)' },
      { q: 'A spring has k = 120 N/m. Calculate the elastic PE stored when it is stretched 0.05 m.', marks: 2, markScheme: '• Eₑ = ½ k x² = ½ × 120 × 0.05² (1)\n• Eₑ = 0.15 J (1)' },
      { q: 'Define efficiency and state its equation.', marks: 2, markScheme: '• Efficiency = useful energy output / total energy input (1)\n• (Or useful power output / total power input) (1)' },
      { q: 'A motor uses 400 J of electrical energy and provides 300 J of useful KE. Calculate its efficiency as a percentage.', marks: 2, markScheme: '• Efficiency = 300/400 = 0.75 (1)\n• 75% (1)' },
      { q: 'Draw a labelled Sankey diagram for an LED lamp where 90% of electrical input is transferred to light.', marks: 3, diagram: true, markScheme: '• Input arrow labelled "electrical" (1)\n• Useful branch (light) ~9× the width of waste branch (heat) (1)\n• Percentages shown; arrows split neatly (1)' },
      { q: 'State two ways unwanted energy transfers from a home can be reduced.', marks: 2, markScheme: '• Loft insulation / cavity wall insulation / double glazing / draught excluders / thicker walls (any 2 = 2)' },
      { q: 'Explain why loft insulation reduces heat loss.', marks: 3, markScheme: '• Fibreglass traps air in small pockets (1)\n• Air is a poor conductor of heat (1)\n• Less heat flows by conduction through the ceiling (1)' },
      { q: 'Explain how double glazing reduces heat loss.', marks: 3, markScheme: '• Two panes of glass with a gas or partial vacuum between (1)\n• The gap is a poor conductor of heat (1)\n• Convection in the gap is also suppressed by the thin layer (1)' },
      { q: 'A £400 loft insulation installation saves £80 per year. Calculate the payback time.', marks: 2, markScheme: '• Time = cost / annual saving = 400 / 80 (1)\n• 5 years (1)' },
      { q: 'Distinguish between renewable and non-renewable energy resources, giving two examples of each.', marks: 4, markScheme: '• Non-renewable: used faster than replaced / will run out (1)\n• Examples: coal / oil / natural gas / nuclear fuel (any 2 = 1)\n• Renewable: replenished naturally faster than used (1)\n• Examples: wind / solar / hydro / tidal / wave / geothermal / biomass (any 2 = 1)' },
      { q: 'Describe how a coal-fired power station generates electricity.', marks: 4, markScheme: '• Coal burnt in a boiler releases thermal energy (1)\n• This heats water to produce steam (1)\n• High-pressure steam turns a turbine (1)\n• Turbine drives a generator which produces electricity (1)' },
      { q: 'Describe how a wind turbine generates electricity.', marks: 3, markScheme: '• Kinetic energy of moving air turns the turbine blades (1)\n• Blades rotate a shaft connected to a generator (1)\n• Generator induces an electric current (1)' },
      { q: 'Compare solar PV and hydroelectric generation in terms of reliability and environmental impact.', marks: 4, markScheme: '• Solar: only works in daylight / intermittent / no CO₂ at point of use / habitat impact small (1)\n• Hydro: very reliable when reservoir full / dispatchable on demand (1)\n• Hydro valley flooding causes habitat loss and methane from rotting vegetation (1)\n• Solar panels are small-scale and modular; hydro needs a specific geography (1)' },
      { q: 'Explain why nuclear power can be called "low-carbon" yet is not classed as renewable.', marks: 3, markScheme: '• Fission releases very little CO₂ per kWh generated → low-carbon (1)\n• But uranium is a finite resource — once mined and used, it is gone (1)\n• Renewable means replenished on human timescales; uranium is not (1)' },
      { q: 'State two disadvantages of nuclear power.', marks: 2, markScheme: '• Long-lived radioactive waste requires safe storage for thousands of years (1)\n• Very high capital and decommissioning costs / accident risk / uranium mining impacts (any 1) (1)' },
      { q: 'Suggest why wind power output varies day to day.', marks: 2, markScheme: '• Wind speeds vary with weather conditions (1)\n• If wind is too slow or too fast turbines produce little or must be shut down (1)' },
      { q: 'Explain why biofuels are sometimes described as "roughly carbon-neutral".', marks: 3, markScheme: '• CO₂ released when burnt was taken in during plant growth by photosynthesis (1)\n• Net CO₂ can be near zero if fuel crops are re-grown (1)\n• Not zero in practice because of processing, transport, land-use change (1)' },
      { q: 'State the rated voltage and frequency of the UK mains supply.', marks: 2, markScheme: '• 230 V (1)\n• 50 Hz (1)' },
      { q: 'Explain why the National Grid uses step-up transformers at power stations and step-down transformers near consumers.', marks: 4, markScheme: '• Step-up increases voltage for transmission (1)\n• Higher voltage means lower current for the same power (1)\n• Lower current reduces I²R heat loss in cables (1)\n• Step-down reduces voltage to safe levels (230 V) at the point of use (1)' },
      { q: 'A 1 kW heater runs for 3 hours per day for 30 days. Calculate the energy used in kWh.', marks: 2, markScheme: '• Energy = 1 × 3 × 30 (1)\n• 90 kWh (1)' },
      { q: 'Electricity costs 30 p per kWh. Calculate the cost of using a 2 kW kettle for 6 minutes.', marks: 3, markScheme: '• Time in hours = 6/60 = 0.1 h (1)\n• Energy = 2 × 0.1 = 0.2 kWh (1)\n• Cost = 0.2 × 30 = 6 p (1)' },
      { q: 'Explain how a thermal imaging camera is used to assess the energy efficiency of a home.', marks: 3, markScheme: '• The camera detects infrared radiation emitted by the building\'s outer surface (1)\n• Warmer areas emit more IR, appearing brighter in the image (1)\n• Bright spots reveal poorly insulated regions (windows, bridges, roof) where heat is escaping (1)' },
      { q: 'A car engine has 30% thermal efficiency and its petrol releases 45 MJ of chemical energy. Calculate the useful KE output.', marks: 2, markScheme: '• Useful = 0.30 × 45 MJ (1)\n• = 13.5 MJ (1)' },
      { q: 'Evaluate the use of tidal barrages compared with offshore wind farms.', marks: 6, markScheme: '• Tidal: predictable output (moon-driven), high capacity factor, long lifetime (1)\n• Tidal: very high capital cost, limited suitable estuaries (1)\n• Tidal: disrupts estuary ecology (silt, fish migration) (1)\n• Wind: widely available offshore, lower capital per MW, scalable (1)\n• Wind: intermittent — needs backup generation, costly maintenance at sea (1)\n• Overall either point-weighted: wind is quicker to deploy and flexible, tidal is a steady baseload contributor (1)' },
      { q: 'State the relationship between power, current and voltage.', marks: 1, markScheme: '• P = V × I (1)' },
      { q: 'A 230 V, 1800 W heater runs for 20 minutes. Calculate the energy used in joules.', marks: 3, markScheme: '• t = 20 × 60 = 1200 s (1)\n• E = P × t = 1800 × 1200 (1)\n• E = 2.16 × 10⁶ J (1)' },
      { q: 'Describe one way electricity demand can be managed during peak times.', marks: 2, markScheme: '• Pumped-storage hydroelectric: water pumped up at off-peak, released during peak to drive turbines (1)\n• Interconnectors import electricity from abroad / battery storage / demand-side response (any alternative valid point) (1)' },
      { q: 'Suggest why geothermal is not widely used in the UK.', marks: 2, markScheme: '• UK has little shallow hot rock / volcanic activity compared with Iceland (1)\n• Drilling deep enough to reach useful temperatures is expensive (1)' },
      { q: 'State one reason why modern LED bulbs are more efficient than traditional filament bulbs.', marks: 1, markScheme: '• LEDs produce light by electroluminescence, not by heating a wire, so little energy is wasted as heat (1)' },
      { q: 'Calculate the efficiency of a filament lamp that wastes 85 J out of every 100 J of electrical input.', marks: 2, markScheme: '• Useful = 100 − 85 = 15 J (1)\n• Efficiency = 15/100 = 15% (1)' },
      { q: 'Describe the energy transfers in a hydroelectric power station.', marks: 3, markScheme: '• Gravitational PE of water stored behind dam → kinetic energy as it falls (1)\n• Kinetic energy turns a turbine (1)\n• Generator converts kinetic energy of turbine to electrical energy (1)' },
      { q: 'State the unit used for the energy content of food/fuel and a typical domestic unit for billing.', marks: 2, markScheme: '• Food/fuel: joule (J) or kilojoule (kJ) (1)\n• Domestic billing: kilowatt-hour (kWh) (1)' },
      { q: 'Evaluate the claim that "switching all homes to electric heating reduces CO₂ emissions".', marks: 4, markScheme: '• True only if the electricity is low-carbon (e.g. wind, nuclear, hydro) (1)\n• If the grid is mainly gas/coal, the overall CO₂ can be similar or higher (1)\n• Heat pumps are more efficient than direct resistive electric heating (1)\n• Decarbonising the grid is needed alongside electrification for the claim to hold (1)' },
    ],
  },

  /* ═══════════════════════════════════════ P3 — Electric Circuits */
  'P3': {
    name: 'Electric Circuits',
    questions: [
      { q: 'State the equation linking charge, current and time.', marks: 1, markScheme: '• Q = I × t (1)' },
      { q: 'State Ohm\'s Law and the equation that represents it.', marks: 2, markScheme: '• Current is directly proportional to the p.d. across an ohmic conductor at constant temperature (1)\n• V = I × R (1)' },
      { q: 'Define potential difference.', marks: 2, markScheme: '• Energy transferred per coulomb of charge passing between two points (1)\n• V = E/Q, in volts (V) (1)' },
      { q: 'Draw the circuit symbols for: cell, switch, lamp, resistor, variable resistor, ammeter, voltmeter, fuse.', marks: 4, diagram: true, markScheme: '• 2 correct symbols (1)\n• 4 correct symbols (2)\n• 6 correct symbols (3)\n• All 8 correct and clearly labelled (4)' },
      { q: 'A current of 0.25 A flows for 5 minutes. Calculate the charge.', marks: 2, markScheme: '• t = 300 s; Q = I t = 0.25 × 300 (1)\n• Q = 75 C (1)' },
      { q: 'A 6 V battery drives 0.5 A through a resistor. Calculate its resistance.', marks: 2, markScheme: '• R = V/I = 6/0.5 (1)\n• R = 12 Ω (1)' },
      { q: 'State three factors that affect the resistance of a metal wire.', marks: 3, markScheme: '• Length — longer wire has more resistance (1)\n• Cross-sectional area — thinner wire has more resistance (1)\n• Material (resistivity) / temperature (1)' },
      { q: 'Describe how to investigate how the resistance of a wire depends on its length.', marks: 5, markScheme: '• Set up circuit: battery, ammeter, voltmeter, wire taped to a metre rule with a crocodile clip (1)\n• Close switch briefly; read V and I at several lengths (e.g. 10–100 cm in 10 cm steps) (1)\n• Calculate R = V/I for each length (1)\n• Keep current low / open switch between readings to avoid heating (1)\n• Plot R vs length — straight line through the origin confirms R ∝ L (1)' },
      { q: 'Draw an I–V graph for a fixed resistor at constant temperature.', marks: 2, diagram: true, markScheme: '• Straight line through the origin (1)\n• Axes labelled: V on x, I on y, with +/− regions (1)' },
      { q: 'Draw and describe the I–V graph for a filament lamp.', marks: 3, diagram: true, markScheme: '• S-shaped curve through origin (1)\n• Gradient decreases as |V| increases — showing resistance rises (1)\n• Explanation: the filament heats up, ions vibrate more, scattering electrons, so R rises (1)' },
      { q: 'Draw and describe the I–V graph for a diode.', marks: 3, diagram: true, markScheme: '• No current (or ~0) for reverse bias and small forward bias (1)\n• Sharp rise in current above ~0.7 V forward (1)\n• Explanation: diode only conducts one way above threshold (1)' },
      { q: 'Describe how the resistance of an LDR changes with light intensity and give one use.', marks: 2, markScheme: '• Resistance decreases as light intensity increases (1)\n• Use: automatic street lights / camera exposure / light-sensing burglar alarms (any 1) (1)' },
      { q: 'Describe how the resistance of a thermistor changes with temperature and give one use.', marks: 2, markScheme: '• Resistance decreases as temperature increases (1)\n• Use: thermostat / fire alarm / protecting electronics from overheating (any 1) (1)' },
      { q: 'State two rules for current and p.d. in a series circuit.', marks: 2, markScheme: '• Current is the same through every component (1)\n• Total p.d. = sum of p.d. across each component (1)' },
      { q: 'State two rules for current and p.d. in a parallel circuit.', marks: 2, markScheme: '• P.d. across each branch is the same and equal to the supply p.d. (1)\n• Total current = sum of currents in each branch (1)' },
      { q: 'Two resistors of 4 Ω and 6 Ω are in series. Calculate the total resistance.', marks: 1, markScheme: '• 10 Ω (1)' },
      { q: 'Two 6 Ω resistors are in parallel. Calculate the total resistance.', marks: 2, markScheme: '• 1/R = 1/6 + 1/6 = 2/6 (1)\n• R = 3 Ω (1)' },
      { q: 'Explain why the total resistance of two resistors in parallel is always less than either of them.', marks: 3, markScheme: '• Adding a parallel branch provides an additional path for current (1)\n• Total current increases for the same p.d. (1)\n• Since R = V/I and V is constant while I increases, R must decrease (1)' },
      { q: 'State the equation linking electrical power, p.d. and current.', marks: 1, markScheme: '• P = V × I (1)' },
      { q: 'A 230 V hairdryer is rated 1150 W. Calculate the current drawn and suggest a suitable fuse (3 A, 5 A or 13 A).', marks: 3, markScheme: '• I = P/V = 1150/230 = 5 A (1)\n• A 13 A fuse is the next standard fuse above 5 A (1)\n• A 3 A or 5 A fuse would blow under normal use (1)' },
      { q: 'Distinguish between direct current (d.c.) and alternating current (a.c.).', marks: 2, markScheme: '• d.c.: current flows one way only; e.g. from a battery (1)\n• a.c.: current periodically reverses direction; e.g. UK mains at 50 Hz (1)' },
      { q: 'Describe the purpose of each of the three wires in a UK three-pin plug.', marks: 3, markScheme: '• Live (brown): carries 230 V a.c. from the mains (1)\n• Neutral (blue): completes the circuit, near 0 V (1)\n• Earth (green/yellow): safety wire to the appliance casing (1)' },
      { q: 'Explain how the earth wire and fuse work together to protect the user if the live wire inside an appliance comes loose.', marks: 4, markScheme: '• If live touches the metal casing, the earth wire offers a low-resistance path to ground (1)\n• A large current flows in the circuit (1)\n• This exceeds the fuse rating so the fuse wire melts and breaks the circuit (1)\n• The appliance is isolated from the live supply — user is safe (1)' },
      { q: 'State two reasons why a.c. (not d.c.) is used for the National Grid.', marks: 2, markScheme: '• Transformers only work with a.c., allowing voltage step-up/down (1)\n• High transmission voltage (low current) reduces I²R losses in cables (1)' },
      { q: 'Draw a circuit diagram showing a battery, a switch and two lamps connected in series, with an ammeter and a voltmeter measuring the second lamp.', marks: 4, diagram: true, markScheme: '• Battery and switch in a series loop (1)\n• Two lamps in series (1)\n• Ammeter in series (correct position) (1)\n• Voltmeter in parallel with second lamp (1)' },
      { q: 'Draw a circuit diagram showing a battery supplying two lamps in parallel.', marks: 3, diagram: true, markScheme: '• Battery connected to two parallel branches (1)\n• Each branch contains one lamp (1)\n• Wires clearly drawn with no short-circuits (1)' },
      { q: 'A 12 V battery drives 0.6 A through a lamp for 2 minutes. Calculate the energy transferred.', marks: 3, markScheme: '• t = 120 s (1)\n• E = V × I × t = 12 × 0.6 × 120 (1)\n• E = 864 J (1)' },
      { q: 'A 100 W filament lamp is replaced with a 12 W LED lamp of similar brightness. Calculate the % energy saving.', marks: 2, markScheme: '• Saving = (100 − 12)/100 = 88% (1)\n• Answer stated as percentage (1)' },
      { q: 'Explain why a kettle is usually supplied with a 13 A fuse but a table lamp with a 3 A fuse.', marks: 3, markScheme: '• Kettle is high power (~2000–3000 W at 230 V → ≈ 9–13 A) so needs 13 A (1)\n• Table lamp is low power (≈ 60 W → ≈ 0.26 A) so a 3 A fuse is ample (1)\n• The fuse must be the smallest standard rating above the normal running current (1)' },
      { q: 'Calculate the energy transferred per second by a 230 V, 2 A appliance and state its power.', marks: 2, markScheme: '• P = V × I = 230 × 2 = 460 W (1)\n• Energy per second = 460 J (1)' },
      { q: 'Explain what is meant by "static electricity" and how it can be produced.', marks: 3, markScheme: '• A build-up of electric charge on an insulator (1)\n• Produced by friction — electrons transferred from one surface to the other (1)\n• One becomes positively charged (loses e⁻), the other negatively (gains e⁻) (1)' },
      { q: 'State whether like charges attract or repel, and give one example of a static-electricity hazard.', marks: 2, markScheme: '• Like charges repel (1)\n• Hazard: sparks during refuelling of aircraft / fuelling of tankers / dust in grain silos (any 1) (1)' },
      { q: 'Calculate the current drawn by a 2 kΩ resistor connected across 12 V.', marks: 2, markScheme: '• I = V/R = 12 / 2000 (1)\n• I = 6 × 10⁻³ A = 6 mA (1)' },
      { q: 'Describe how increasing the temperature affects the resistance of a metal wire and explain why.', marks: 3, markScheme: '• Resistance increases as temperature rises (1)\n• Ions in the lattice vibrate more vigorously (1)\n• Electrons collide more often with ions → higher resistance (1)' },
      { q: 'A wire of length L has resistance R. A new wire is made twice as long with half the cross-sectional area. State the new resistance.', marks: 2, markScheme: '• R ∝ L and R ∝ 1/A (1)\n• New resistance = R × 2 / 0.5 = 4R (1)' },
      { q: 'Explain why a kettle boils faster when connected to 230 V than to 115 V (assuming constant R).', marks: 3, markScheme: '• P = V²/R — power is proportional to V² (1)\n• Halving voltage reduces power to a quarter (1)\n• So less energy per second → takes ≈ 4× longer to reach boiling (1)' },
      { q: 'Describe one use of static electricity.', marks: 2, markScheme: '• Photocopier / laser printer: toner attracted to charged drum (1)\n• Or: electrostatic paint sprayer — charged droplets coat an earthed object evenly (1)' },
      { q: 'State Kirchhoff\'s 1st Law (current at a junction) and 2nd Law (p.d. around a loop).', marks: 2, markScheme: '• Current in = current out at any junction (charge conservation) (1)\n• Sum of p.d.s around a loop = 0 (energy conservation) (1)' },
      { q: 'Evaluate the statement: "A parallel circuit is always safer than a series circuit in a home."', marks: 4, markScheme: '• Parallel: each appliance gets the full mains p.d. → works at its rated power (1)\n• If one appliance fails/switches off, others keep working — more practical (1)\n• Individual switches/fuses can isolate each branch, improving safety (1)\n• In series, a fault in one appliance would stop the whole house; so parallel is preferable (1)' },
      { q: '"Voltage causes current." Explain whether this simple statement is a good model for Ohm\'s Law.', marks: 6, markScheme: '• It captures the idea that a p.d. across a conductor drives a flow of charge (1)\n• It matches V = IR for ohmic components at constant T (1)\n• However, p.d. does not directly "cause" current — both relate to energy transfer (1)\n• Current is the rate of charge flow; p.d. is the energy per charge between two points (1)\n• Many components are non-ohmic (filament lamp, diode, thermistor) — resistance varies (1)\n• So the statement is a useful first approximation but incomplete for real components (1)' },
    ],
  },

  /* ═══════════════════════════════════════ P4 — Explaining Motion */
  'P4': {
    name: 'Explaining Motion',
    questions: [
      { q: 'Distinguish between a scalar and a vector quantity. Give one example of each.', marks: 3, markScheme: '• Scalar has magnitude only; vector has magnitude and direction (1)\n• Example scalar: distance / speed / mass / time / energy (any 1) (1)\n• Example vector: displacement / velocity / force / momentum / acceleration (any 1) (1)' },
      { q: 'Define speed and state its unit.', marks: 2, markScheme: '• Distance travelled per unit time (1)\n• Unit: m/s (1)' },
      { q: 'State the equation for acceleration.', marks: 1, markScheme: '• a = (v − u) / t (or Δv/Δt) (1)' },
      { q: 'A car accelerates from rest to 24 m/s in 8 s. Calculate its acceleration.', marks: 2, markScheme: '• a = (24 − 0)/8 (1)\n• a = 3 m/s² (1)' },
      { q: 'State typical speeds of: walking, cycling, a car on the motorway, and sound in air.', marks: 4, markScheme: '• Walking ~1.5 m/s (1)\n• Cycling ~6 m/s (1)\n• Motorway ~31 m/s / 70 mph (1)\n• Sound in air ~340 m/s (1)' },
      { q: 'Sketch a distance–time graph for an object at rest, then moving at constant speed, then accelerating.', marks: 3, diagram: true, markScheme: '• Horizontal section (rest) (1)\n• Straight positive slope (constant speed) (1)\n• Curve with increasing gradient (accelerating) (1)' },
      { q: 'Sketch a velocity–time graph for an object that accelerates uniformly, moves at constant speed, then decelerates uniformly to rest.', marks: 3, diagram: true, markScheme: '• Straight rise (acceleration) (1)\n• Horizontal line (constant v) (1)\n• Straight fall back to zero (deceleration) (1)' },
      { q: 'Explain what the area under a velocity–time graph represents.', marks: 2, markScheme: '• Distance travelled (1)\n• Because area = v × t (for a rectangle) which is distance (1)' },
      { q: 'Explain what the gradient of a velocity–time graph represents.', marks: 1, markScheme: '• Acceleration (1)' },
      { q: 'State Newton\'s First Law.', marks: 2, markScheme: '• An object remains at rest, or moves at constant velocity, unless (1)\n• acted on by a resultant force (1)' },
      { q: 'State Newton\'s Second Law and write its equation.', marks: 2, markScheme: '• Resultant force on an object = mass × acceleration (1)\n• F = m a (1)' },
      { q: 'State Newton\'s Third Law.', marks: 2, markScheme: '• When object A exerts a force on object B, object B exerts an equal and opposite force on A (1)\n• The forces act on different objects (1)' },
      { q: 'Explain the difference between mass and weight.', marks: 2, markScheme: '• Mass is the amount of matter in an object, in kilograms; it does not change with location (1)\n• Weight is the gravitational force on that mass, W = mg, in newtons; depends on g (1)' },
      { q: 'A 75 kg skier has weight W on Earth (g = 9.8 N/kg). Calculate W.', marks: 2, markScheme: '• W = m g = 75 × 9.8 (1)\n• W = 735 N (1)' },
      { q: 'A resultant force of 2000 N acts on an 800 kg car. Calculate the acceleration.', marks: 2, markScheme: '• a = F/m = 2000/800 (1)\n• a = 2.5 m/s² (1)' },
      { q: 'Describe what happens to a skydiver\'s motion from the moment they jump until they open the parachute.', marks: 5, markScheme: '• Initially only weight acts → they accelerate at ~g (1)\n• Air resistance grows as speed increases (1)\n• Resultant force decreases and acceleration decreases (1)\n• When air resistance = weight, resultant = 0 and they fall at terminal velocity (1)\n• Parachute opens: drag > weight suddenly → they decelerate before reaching a new, lower terminal velocity (1)' },
      { q: 'Draw a free-body diagram of a car moving at constant velocity on a flat road.', marks: 3, diagram: true, markScheme: '• Weight arrow down and normal reaction arrow up, equal lengths (1)\n• Driving force forward and resistive force (friction + drag) backward, equal lengths (1)\n• Clear labels on all four arrows (1)' },
      { q: 'State the equation for momentum and its unit.', marks: 2, markScheme: '• p = m × v (1)\n• Unit: kg·m/s (1)' },
      { q: 'A 0.5 kg ball moving at 4 m/s collides with and sticks to a stationary 1.5 kg ball. Calculate their common speed after.', marks: 3, markScheme: '• Momentum before = 0.5 × 4 + 0 = 2 kg m/s (1)\n• Momentum after = (0.5 + 1.5) × v (1)\n• v = 2 / 2 = 1 m/s (1)' },
      { q: 'Explain how a seat belt reduces injury in a crash.', marks: 3, markScheme: '• Belt stretches, increasing the time over which the body\'s momentum falls to zero (1)\n• F = Δp/Δt, so a larger t gives a smaller force (1)\n• The force is spread over the strong torso (ribs, hips) rather than hitting the windscreen (1)' },
      { q: 'A 1.2 kg cricket ball moving at 20 m/s is caught in 0.04 s. Calculate the average force on the ball.', marks: 3, markScheme: '• Δp = m(v − u) = 1.2 × (0 − 20) = −24 kg m/s (1)\n• F = Δp/Δt = 24 / 0.04 (1)\n• F = 600 N (1)' },
      { q: 'Define stopping distance and state its two parts.', marks: 2, markScheme: '• Total distance between the driver seeing a hazard and the car stopping (1)\n• = thinking distance + braking distance (1)' },
      { q: 'State two factors that increase thinking distance.', marks: 2, markScheme: '• Higher speed / tiredness / alcohol or drugs / distractions (phone, loud music) (any 2 = 2)' },
      { q: 'State two factors that increase braking distance.', marks: 2, markScheme: '• Higher speed / wet or icy road / worn brakes / worn tyres / heavier load (any 2 = 2)' },
      { q: 'Explain why braking distance increases more than proportionally with speed.', marks: 3, markScheme: '• Kinetic energy ½ m v² must be dissipated by the brakes (1)\n• Doubling speed → 4× kinetic energy (1)\n• For the same braking force, distance ≈ 4× (since F × d = KE) (1)' },
      { q: 'State Hooke\'s Law and its equation.', marks: 2, markScheme: '• Extension of an elastic object is proportional to the force applied (within the limit of proportionality) (1)\n• F = k × x (1)' },
      { q: 'A 50 N force stretches a spring by 0.2 m. Calculate its spring constant.', marks: 2, markScheme: '• k = F/x = 50/0.2 (1)\n• k = 250 N/m (1)' },
      { q: 'Draw a force–extension graph for a spring that is stretched beyond its limit of proportionality.', marks: 3, diagram: true, markScheme: '• Straight line through origin up to a marked limit (1)\n• Curve that starts to flatten beyond the limit (1)\n• Limit of proportionality clearly labelled (1)' },
      { q: 'A spring with k = 40 N/m is stretched by 0.1 m. Calculate the elastic PE stored.', marks: 2, markScheme: '• Eₑ = ½ k x² = ½ × 40 × 0.01 (1)\n• Eₑ = 0.2 J (1)' },
      { q: 'Define a moment and state its unit.', marks: 2, markScheme: '• Turning effect of a force about a pivot = force × perpendicular distance from pivot (1)\n• Unit: newton metre (N m) (1)' },
      { q: 'State the principle of moments.', marks: 2, markScheme: '• For a body in equilibrium, total clockwise moments about any point = total anticlockwise moments (1)\n• About the same point (1)' },
      { q: 'A 600 N child sits 1.2 m from the pivot of a see-saw. Where must a 400 N child sit to balance?', marks: 3, markScheme: '• Clockwise moment = 600 × 1.2 = 720 N m (1)\n• For balance, 400 × d = 720 (1)\n• d = 1.8 m on the opposite side (1)' },
      { q: 'Explain why a long spanner is easier to use than a short one when loosening a tight nut.', marks: 3, markScheme: '• Moment = force × distance from pivot (1)\n• A longer spanner increases the distance (1)\n• So a smaller applied force produces the same turning moment (1)' },
      { q: 'Describe what is meant by "terminal velocity".', marks: 2, markScheme: '• Steady maximum velocity reached when drag/friction = weight (1)\n• Resultant force is zero, so acceleration is zero (1)' },
      { q: 'A car of mass 1200 kg decelerates from 20 m/s to rest in 5 s. Calculate the average braking force.', marks: 3, markScheme: '• a = (0 − 20)/5 = −4 m/s² (1)\n• F = m a = 1200 × 4 (1)\n• F = 4800 N (backwards) (1)' },
      { q: 'Using v² = u² + 2as, find the speed of a car that starts at 10 m/s and accelerates at 2 m/s² over 40 m.', marks: 3, markScheme: '• v² = 10² + 2 × 2 × 40 = 100 + 160 (1)\n• v² = 260 (1)\n• v ≈ 16.1 m/s (1)' },
      { q: 'Explain why cyclists lean forwards and wear tight-fitting clothes when racing.', marks: 3, markScheme: '• Reduces cross-sectional area exposed to airflow (1)\n• Smooth, tight clothing reduces drag coefficient / turbulence (1)\n• Lower drag → higher top speed for the same power output (1)' },
      { q: 'State two differences between elastic and inelastic collisions.', marks: 2, markScheme: '• Both conserve momentum; only elastic conserves kinetic energy (1)\n• In inelastic some KE becomes internal/heat/sound; objects may stick (1)' },
      { q: 'A 0.2 kg ball hits a wall at 30 m/s and rebounds at 20 m/s in the opposite direction. Calculate the change in momentum.', marks: 3, markScheme: '• Take initial as +30, final as −20 (1)\n• Δp = m(v − u) = 0.2 × (−20 − 30) (1)\n• Δp = −10 kg m/s (magnitude 10 kg m/s) (1)' },
      { q: 'Explain, using physics, why drivers are required to follow the two-second rule (a gap of at least 2 s behind the car ahead).', marks: 5, markScheme: '• Drivers need thinking time to react — typical reaction time ~0.7 s (1)\n• At 31 m/s (70 mph) a car travels ~22 m in 0.7 s of thinking (1)\n• Braking distance adds ~75 m, total stopping distance ~96 m (1)\n• A two-second gap gives ≈ 62 m cushion at 70 mph, roughly enough to stop before the car ahead in normal conditions (1)\n• In wet/icy conditions the rule should extend to 4 s because braking distance grows (1)' },
    ],
  },

  /* ═══════════════════════════════════════ P5 — Radioactive Materials */
  'P5': {
    name: 'Radioactive Materials',
    questions: [
      { q: 'Describe the structure of an atom including the approximate sizes.', marks: 3, markScheme: '• Dense positive nucleus containing protons and neutrons (1)\n• Electrons orbit in shells around the nucleus (1)\n• Nucleus radius ~10⁻¹⁴ m vs atom ~10⁻¹⁰ m — atom ~10 000× larger than its nucleus (1)' },
      { q: 'State the relative mass and relative charge of proton, neutron and electron.', marks: 3, markScheme: '• Proton: mass 1, charge +1 (1)\n• Neutron: mass 1, charge 0 (1)\n• Electron: mass ~1/1836 (≈ 0), charge −1 (1)' },
      { q: 'Describe the plum pudding model and explain why it was rejected.', marks: 4, markScheme: '• Atom = sphere of positive matter with electrons dotted through it (1)\n• Could not explain the large-angle backscatter of alpha particles (1)\n• Rutherford\'s scattering showed a small, dense, positive nucleus (1)\n• So the plum pudding model was replaced with the nuclear model (1)' },
      { q: 'Describe Rutherford\'s gold-foil scattering experiment and its conclusions.', marks: 6, markScheme: '• Beam of α-particles fired at thin gold foil (1)\n• Detector measured deflections around the foil (1)\n• Most passed through — atoms mostly empty (1)\n• A few deflected — small, positive nucleus repelled them (1)\n• Very few bounced back — nucleus is small but very dense (1)\n• Concluded nuclear model: small dense positive core with electrons around (1)' },
      { q: 'Define the atomic number and mass number of a nucleus.', marks: 2, markScheme: '• Atomic (proton) number Z: number of protons (1)\n• Mass (nucleon) number A: total protons + neutrons (1)' },
      { q: 'Define "isotope".', marks: 2, markScheme: '• Atoms of the same element (same Z) (1)\n• With different numbers of neutrons (different A) (1)' },
      { q: 'Name the three main types of nuclear radiation and state what each is.', marks: 3, markScheme: '• Alpha: helium nucleus (2p + 2n) (1)\n• Beta-minus: fast-moving electron from the nucleus (1)\n• Gamma: high-frequency EM wave/photon (1)' },
      { q: 'Compare the penetrating ability and ionising ability of alpha, beta and gamma.', marks: 6, markScheme: '• Penetration: α lowest (stopped by paper/few cm air/skin) (1)\n• Penetration: β medium (stopped by a few mm aluminium) (1)\n• Penetration: γ greatest (reduced by lead/concrete, never fully stopped) (1)\n• Ionising: α strongest (1)\n• Ionising: β moderate (1)\n• Ionising: γ weakest (1)' },
      { q: 'Complete the alpha decay: ²²⁶₈₈Ra → ? + ⁴₂He.', marks: 2, markScheme: '• Daughter: ²²²₈₆Rn (radon-222) (1)\n• Mass number conserved 226 = 222+4; proton conserved 88 = 86+2 (1)' },
      { q: 'Complete the beta-minus decay: ¹⁴₆C → ? + ⁰₋₁e.', marks: 2, markScheme: '• Daughter: ¹⁴₇N (nitrogen-14) (1)\n• Mass 14 unchanged; proton rises by 1 since a neutron becomes a proton (1)' },
      { q: 'Describe what happens to the mass number and proton number when a nucleus emits a gamma ray.', marks: 2, markScheme: '• Both are unchanged (1)\n• Gamma emission releases energy from the nucleus without changing A or Z (1)' },
      { q: 'Define activity and state its unit.', marks: 2, markScheme: '• Activity = number of nuclear decays per second (1)\n• Unit: becquerel (Bq) (1)' },
      { q: 'Define half-life.', marks: 1, markScheme: '• Time for the activity (or number of undecayed nuclei) to fall to half its original value (1)' },
      { q: 'A sample starts at 8000 Bq and has a half-life of 5 hours. Calculate its activity after 20 hours.', marks: 3, markScheme: '• Number of half-lives = 20/5 = 4 (1)\n• A = 8000 × (½)⁴ = 8000/16 (1)\n• A = 500 Bq (1)' },
      { q: 'Draw a typical decay curve of activity against time and mark two half-lives.', marks: 4, diagram: true, markScheme: '• Smooth exponential decay curve from high to approaching zero (1)\n• Axes labelled time (x) and activity (y) (1)\n• First half-life marked where A has dropped to ½ (1)\n• Second half-life at A = ¼ (1)' },
      { q: 'State two major natural sources of background radiation.', marks: 2, markScheme: '• Radon gas from rocks/soil (1)\n• Cosmic rays / food and drink / rocks and soil (any 1 more) (1)' },
      { q: 'Explain why background radiation must be measured and subtracted when using a Geiger counter.', marks: 3, markScheme: '• Background is always present and adds to any reading (1)\n• Without subtraction, measured count rates are systematically too high (1)\n• Subtracting background isolates the genuine contribution from the source (1)' },
      { q: 'Distinguish between irradiation and contamination.', marks: 3, markScheme: '• Irradiation: exposure to radiation from an external source — the object does not become radioactive (1)\n• Contamination: radioactive material is on or inside the body/object (1)\n• Contamination is harder to stop because the source travels with the body (1)' },
      { q: 'Explain why inside the body, alpha is the most dangerous radiation, but outside the body gamma is the most dangerous.', marks: 4, markScheme: '• Alpha is highly ionising but short range (1)\n• Inside the body it deposits all its energy in nearby cells → maximum damage (1)\n• Gamma is penetrating and weakly ionising (1)\n• Outside the body gamma can still reach internal organs, while alpha cannot penetrate the skin (1)' },
      { q: 'State one medical use of gamma radiation.', marks: 1, markScheme: '• Medical tracer / sterilising equipment / radiotherapy (any 1) (1)' },
      { q: 'Explain why technetium-99m (γ emitter, half-life 6 h) is a good choice of medical tracer.', marks: 3, markScheme: '• γ penetrates tissue to reach an external detector (1)\n• Short half-life means the patient\'s exposure decreases quickly after the scan (1)\n• Can be prepared on demand and excreted naturally, minimising dose (1)' },
      { q: 'State one everyday use of alpha radiation.', marks: 1, markScheme: '• Smoke detectors (americium-241) (1)' },
      { q: 'Describe how a smoke detector uses alpha radiation.', marks: 4, markScheme: '• Americium-241 emits α particles into a small ionisation chamber (1)\n• This ionises air between two plates, allowing a tiny current to flow (1)\n• Smoke particles absorb α and reduce the ionisation, cutting the current (1)\n• The circuit detects the drop and sets off the alarm (1)' },
      { q: 'State one industrial use of beta radiation.', marks: 1, markScheme: '• Thickness monitoring of paper/foil during manufacture (1)' },
      { q: 'Describe how beta radiation is used to monitor the thickness of paper in a factory.', marks: 3, markScheme: '• β source on one side of the paper, detector on the other (1)\n• Amount of β transmitted depends on paper thickness (1)\n• If detector reading changes, rollers adjust to restore correct thickness (1)' },
      { q: 'Explain why γ rather than α would be unsuitable in a smoke detector.', marks: 3, markScheme: '• γ is highly penetrating, so most would escape the detector without being absorbed by smoke (1)\n• The signal change from smoke would be tiny (1)\n• α has very short range in air, so smoke in the chamber has a clear effect (1)' },
      { q: 'State the difference between nuclear fission and nuclear fusion.', marks: 2, markScheme: '• Fission: a large nucleus splits into smaller ones (1)\n• Fusion: two small nuclei join to form a larger one (1)' },
      { q: 'Describe a fission chain reaction.', marks: 4, markScheme: '• A uranium-235 nucleus absorbs a slow neutron and becomes unstable (1)\n• It splits into two smaller nuclei plus 2–3 neutrons and releases energy (1)\n• These neutrons go on to cause further fissions (1)\n• In a reactor, control rods absorb some neutrons to keep the rate steady (1)' },
      { q: 'Explain why fusion is hard to achieve on Earth.', marks: 3, markScheme: '• Nuclei are positively charged and repel each other (electrostatically) (1)\n• Needs extremely high temperatures (~10⁷ K) to overcome repulsion (1)\n• Containing a plasma hot enough is technologically challenging (1)' },
      { q: 'Explain the source of the Sun\'s energy.', marks: 2, markScheme: '• Nuclear fusion of hydrogen to helium in the core (1)\n• A small mass loss is converted into a very large amount of energy (E = mc²) (1)' },
      { q: 'Explain how C-14 dating works for organic material.', marks: 4, markScheme: '• Living organisms exchange carbon with the atmosphere and maintain a constant C-14/C-12 ratio (1)\n• After death, exchange stops and C-14 decays with a known half-life (~5730 years) (1)\n• Measuring the remaining C-14 activity gives the age (1)\n• Works best for items up to ~50 000 years old (too old → too little C-14 left) (1)' },
      { q: 'A sample has initial activity 1600 Bq and half-life 30 s. Sketch its activity for the first 120 s.', marks: 4, diagram: true, markScheme: '• Axes labelled time and activity, with 1600 Bq at t=0 (1)\n• Value at 30 s = 800, 60 s = 400, 90 s = 200, 120 s = 100 (1)\n• Smooth decay curve connecting points (1)\n• Clearly decreasing but never reaching zero (1)' },
      { q: 'Describe two methods used to minimise the dose to medical staff when handling radioactive sources.', marks: 2, markScheme: '• Use tongs/remote-handling to increase distance (1)\n• Wear lead aprons / stand behind lead screens / limit exposure time (any 1 further) (1)' },
      { q: 'Explain why a CT scan uses a higher dose than a chest X-ray and why it is still worth it.', marks: 3, markScheme: '• CT uses many X-ray projections from different angles → total dose much higher (1)\n• But produces detailed 3-D images that are much more informative (1)\n• The diagnostic benefit may outweigh the small increased cancer risk (1)' },
      { q: 'Explain why positrons released in a PET scan can be detected outside the body.', marks: 3, markScheme: '• Positron annihilates with a nearby electron (1)\n• Produces two γ rays travelling in opposite directions (1)\n• γ rays are penetrating and reach detectors around the patient (1)' },
      { q: 'State what happens to mass and proton number in positron (β⁺) decay.', marks: 2, markScheme: '• Mass number unchanged (1)\n• Proton number decreases by 1 (a proton becomes a neutron + β⁺) (1)' },
      { q: 'A radioactive source has a half-life of 2 hours. Calculate how long until its activity falls to 1/32 of its original value.', marks: 3, markScheme: '• (½)ⁿ = 1/32 → n = 5 half-lives (1)\n• Time = 5 × 2 h (1)\n• Time = 10 hours (1)' },
      { q: 'Evaluate the use of nuclear power in the UK energy mix.', marks: 6, markScheme: '• Reliable baseload — generates at rated output nearly all the time (1)\n• Very low CO₂ per kWh (around 12 g CO₂/kWh lifecycle) (1)\n• High energy density → small fuel usage (1)\n• However: very high capital and decommissioning costs (1)\n• Long-lived radioactive waste needs secure long-term storage (1)\n• Risk, though small, of severe accidents — requires extensive safety systems (1)' },
      { q: 'Explain why nuclear waste is dangerous for a long time.', marks: 3, markScheme: '• Many products have long half-lives (hundreds to millions of years) (1)\n• They continue to emit ionising radiation over that time (1)\n• So storage must be secure for timescales longer than human civilisations (1)' },
      { q: '"Radioactive decay is random but predictable." Explain this statement.', marks: 4, markScheme: '• Individual decays cannot be predicted — which nucleus and when (1)\n• But for a large sample the proportion decaying per unit time is constant (1)\n• The half-life is a reliable statistical property (1)\n• So population behaviour is predictable even though individual events are not (1)' },
    ],
  },

  /* ═══════════════════════════════════════ P6 — Matter — Models and Explanations */
  'P6': {
    name: 'Matter — Models and Explanations',
    questions: [
      { q: 'Describe the particle arrangement in a solid, liquid and gas.', marks: 3, markScheme: '• Solid: particles closely packed in a regular pattern, vibrating in place (1)\n• Liquid: particles close but irregular, sliding past each other (1)\n• Gas: particles far apart, random, fast motion (1)' },
      { q: 'Draw a labelled diagram showing particle arrangements in solids, liquids and gases.', marks: 4, diagram: true, markScheme: '• Solid: grid of touching circles in a regular pattern (1)\n• Liquid: circles touching but random positions (1)\n• Gas: widely spread circles with motion arrows (1)\n• All three labelled correctly (1)' },
      { q: 'Define density and state its equation.', marks: 2, markScheme: '• Density = mass per unit volume (1)\n• ρ = m / V (1)' },
      { q: 'A block has mass 540 g and volume 200 cm³. Calculate its density in g/cm³.', marks: 2, markScheme: '• ρ = 540/200 (1)\n• ρ = 2.7 g/cm³ (1)' },
      { q: 'Convert a density of 2.7 g/cm³ into kg/m³.', marks: 2, markScheme: '• Multiply by 1000 (1)\n• 2700 kg/m³ (1)' },
      { q: 'Describe how to measure the density of an irregular solid.', marks: 5, markScheme: '• Weigh the object on a top-pan balance (1)\n• Fill a eureka can to the spout with water (1)\n• Place a measuring cylinder under the spout (1)\n• Lower object in; collect displaced water — volume of water = volume of object (1)\n• ρ = m / V (1)' },
      { q: 'Describe how to measure the density of a liquid.', marks: 3, markScheme: '• Place empty measuring cylinder on balance and zero it (1)\n• Pour liquid in; read volume and mass together (1)\n• ρ = m / V (1)' },
      { q: 'Explain why ice floats on water.', marks: 2, markScheme: '• Ice (density ~917 kg/m³) is less dense than water (1000 kg/m³) (1)\n• Upthrust from water exceeds ice\'s weight → it floats (1)' },
      { q: 'Explain what is meant by internal energy.', marks: 2, markScheme: '• Total energy of all particles in a substance (1)\n• Sum of their kinetic and potential energies (1)' },
      { q: 'Explain why the temperature of ice does not rise while it is melting, even when heat is supplied.', marks: 3, markScheme: '• Energy is used to break intermolecular bonds / increase particle PE (1)\n• Average kinetic energy of particles stays the same (1)\n• Temperature depends on average KE, so it stays constant (1)' },
      { q: 'Sketch a heating curve for water from −10 °C to 110 °C, labelling the plateaus.', marks: 4, diagram: true, markScheme: '• Rising slope ice → 0 °C (1)\n• Plateau at 0 °C (melting) (1)\n• Rising slope water → 100 °C (1)\n• Plateau at 100 °C (boiling) and final rising slope for steam (1)' },
      { q: 'State the equation for heat energy and name its terms.', marks: 2, markScheme: '• ΔE = m × c × Δθ (1)\n• m = mass (kg), c = specific heat capacity (J/kg °C), Δθ = temperature change (°C) (1)' },
      { q: 'Calculate the energy needed to heat 2 kg of water from 20 °C to 100 °C. Take c = 4200 J/kg °C.', marks: 2, markScheme: '• ΔE = 2 × 4200 × 80 (1)\n• ΔE = 672 000 J (672 kJ) (1)' },
      { q: 'State the equation for specific latent heat.', marks: 1, markScheme: '• E = m × L (1)' },
      { q: 'Calculate the energy to completely boil 0.5 kg of water at 100 °C. Take L_v = 2.26 × 10⁶ J/kg.', marks: 2, markScheme: '• E = m L_v = 0.5 × 2.26 × 10⁶ (1)\n• E = 1.13 × 10⁶ J (1)' },
      { q: 'Explain why water is used in the central heating system of a home.', marks: 3, markScheme: '• Water has a very high specific heat capacity (1)\n• So it can carry a lot of thermal energy per kg (1)\n• It is also cheap, safe and readily available (1)' },
      { q: 'Define pressure and state its equation and unit.', marks: 2, markScheme: '• Pressure = force per unit area, p = F/A (1)\n• Unit: pascal (Pa) = N/m² (1)' },
      { q: 'A 400 N force is applied to an area of 0.02 m². Calculate the pressure.', marks: 2, markScheme: '• p = F/A = 400 / 0.02 (1)\n• p = 20 000 Pa (20 kPa) (1)' },
      { q: 'Explain why pressure inside a fluid increases with depth.', marks: 3, markScheme: '• Pressure at a depth is due to the weight of fluid above that point (1)\n• Greater depth → more fluid above → more weight per unit area (1)\n• So pressure rises with depth (p = h ρ g) (1)' },
      { q: 'Calculate the pressure at 20 m depth in seawater (ρ = 1025 kg/m³, g = 10 N/kg).', marks: 2, markScheme: '• p = h ρ g = 20 × 1025 × 10 (1)\n• p = 205 000 Pa (205 kPa) (1)' },
      { q: 'Explain the origin of upthrust on an object submerged in a fluid.', marks: 3, markScheme: '• Pressure in a fluid increases with depth (1)\n• The pressure on the lower surface of the object is greater than on its upper surface (1)\n• This produces a net upward force = weight of fluid displaced (Archimedes\' principle) (1)' },
      { q: 'State Archimedes\' principle and use it to explain why a ship floats.', marks: 3, markScheme: '• Upthrust = weight of fluid displaced (1)\n• A ship\'s shape displaces a large volume of water (1)\n• When the weight of displaced water equals the ship\'s weight, upthrust balances weight and it floats (1)' },
      { q: 'Explain why atmospheric pressure decreases with altitude.', marks: 3, markScheme: '• Atmospheric pressure is the weight of the air column above (1)\n• At higher altitudes less air remains above (1)\n• So the weight per unit area (pressure) is less (1)' },
      { q: 'Explain why your ears pop when a plane takes off or lands.', marks: 3, markScheme: '• External air pressure changes quickly (1)\n• Pressure inside the middle ear equalises more slowly via the Eustachian tube (1)\n• The small pressure difference is felt and released as a "pop" (1)' },
      { q: 'State Boyle\'s Law in words and as an equation.', marks: 2, markScheme: '• For a fixed mass of gas at constant temperature, pressure × volume is constant (1)\n• p₁ V₁ = p₂ V₂ (1)' },
      { q: 'A gas occupies 500 cm³ at 100 kPa. What pressure will it have at constant temperature when compressed to 200 cm³?', marks: 3, markScheme: '• p₁ V₁ = p₂ V₂ (1)\n• p₂ = (100 × 500) / 200 (1)\n• p₂ = 250 kPa (1)' },
      { q: 'Explain, using the particle model, why compressing a gas at constant temperature increases its pressure.', marks: 3, markScheme: '• Particles are confined to a smaller volume (1)\n• They collide with the walls more frequently (1)\n• More force per unit area → higher pressure (1)' },
      { q: 'Explain, using the particle model, why heating a gas at constant volume increases its pressure.', marks: 3, markScheme: '• Particles gain kinetic energy and move faster (1)\n• Collide with walls more frequently and more forcefully (1)\n• Force per unit area increases → pressure rises (1)' },
      { q: 'Explain why a bike pump gets hot when used rapidly.', marks: 3, markScheme: '• Work is done on the gas by the piston, increasing its internal energy (1)\n• Faster particles → higher temperature (1)\n• Heat is conducted through the pump walls, which feel warm (1)' },
      { q: 'State Hooke\'s Law and name the limit beyond which it no longer applies.', marks: 2, markScheme: '• F = k × x (within elastic region) (1)\n• No longer holds beyond the limit of proportionality / elastic limit (1)' },
      { q: 'Distinguish between elastic and plastic deformation.', marks: 2, markScheme: '• Elastic: object returns to original shape when force is removed (1)\n• Plastic: object is permanently deformed after force is removed (1)' },
      { q: 'Draw and label a force–extension graph for a spring showing both the elastic and plastic regions.', marks: 4, diagram: true, markScheme: '• Straight line through origin for elastic region (1)\n• Curve that flattens beyond limit (plastic) (1)\n• Limit of proportionality labelled (1)\n• Axes and regions clearly labelled (1)' },
      { q: 'A 10 N force stretches a spring by 0.05 m. Within its elastic region, calculate the spring constant k and the extension under a 25 N force.', marks: 3, markScheme: '• k = F/x = 10/0.05 = 200 N/m (1)\n• New extension x = F/k = 25/200 (1)\n• x = 0.125 m (12.5 cm) (1)' },
      { q: 'Explain why bridge cables are made of steel rather than rubber.', marks: 3, markScheme: '• Steel has a very high Young\'s modulus / spring constant — stretches very little under load (1)\n• Steel has a high elastic limit and yield strength — withstands large forces without permanent deformation (1)\n• Rubber would stretch too much and lose elasticity under continuous heavy loads (1)' },
      { q: 'A sealed gas cools from 300 K to 100 K at constant volume. Calculate the ratio of new to old pressure.', marks: 3, markScheme: '• p/T = constant at constant V (1)\n• p₂/p₁ = T₂/T₁ = 100/300 (1)\n• Ratio = 1/3 (1)' },
      { q: 'Explain why a hot-air balloon rises.', marks: 3, markScheme: '• Heating air inside the balloon lowers its density (particles move apart) (1)\n• Weight of displaced cooler outside air > weight of the balloon + hot air (1)\n• Upthrust exceeds weight, so balloon rises (1)' },
      { q: 'Calculate the mass of a 2 m³ block of aluminium (ρ = 2700 kg/m³).', marks: 2, markScheme: '• m = ρ V = 2700 × 2 (1)\n• m = 5400 kg (1)' },
      { q: 'Explain why putting a lid on a pan of boiling water increases the pressure inside slightly.', marks: 3, markScheme: '• Steam cannot escape so accumulates in the closed space (1)\n• More gas particles → more collisions with the walls (1)\n• Pressure rises slightly until the lid lifts momentarily to release steam (1)' },
      { q: 'Explain, using the particle model, why evaporation cools the remaining liquid.', marks: 3, markScheme: '• Fastest (highest-KE) particles escape from the surface (1)\n• Average KE of remaining particles drops (1)\n• Temperature (measure of average KE) therefore falls (1)' },
      { q: 'Evaluate whether a gas can ever be considered to obey Boyle\'s Law perfectly.', marks: 6, markScheme: '• Boyle\'s Law assumes ideal gas: point particles, no forces, elastic collisions (1)\n• Real gases have finite volume particles and intermolecular forces (1)\n• At low pressure and high temperature, real gases behave almost ideally (1)\n• At high pressure / low temperature, deviations become significant (gas may liquefy) (1)\n• So Boyle\'s Law is an excellent approximation, not an exact truth (1)\n• Useful in most GCSE/engineering problems but not at extremes (1)' },
    ],
  },

};

